// Get incoming data
const body = $input.item.json.body;
const sessionId = body.sessionId || body.userId;
const currentMessage = body.message;
const history = body.history || [];
const financialData = body.financialData || {};
const isVoiceInput = body.isVoiceInput || false;

// Early validation
if (!currentMessage || !sessionId) {
  return { json: { error: 'Missing required fields: message or sessionId' } };
}

console.log('=== SESSION INFO ===');
console.log('Session ID:', sessionId);
console.log('Current Message:', currentMessage);
console.log('History Length:', history.length);
console.log('Financial Data Available:', Object.keys(financialData).length > 0);
console.log('Has Financial Clarity:', !!financialData.financialClaritySummary);
console.log('Has Investments:', !!financialData.investments?.length);
console.log('Is Voice Input:', isVoiceInput);
console.log('===================');

// Cache frequently used values
const hasFinancialData = Object.keys(financialData).length > 0;
const hasHistory = history.length > 0;
const hasRiskProfile = !!financialData.riskProfile;
const hasGoals = financialData.goals?.length > 0;
const hasAssets = financialData.assets?.length > 0;
const hasLiabilities = financialData.liabilities?.length > 0;
const hasClarityAssessment = !!financialData.financialClaritySummary;
const hasInvestments = financialData.investments?.length > 0;

// Helper Functions
function formatCurrency(amount) {
  return `Rs. ${(amount || 0).toLocaleString('en-IN')}`;
}

function buildConversationHistory() {
  if (!hasHistory) return '';

  const historyParts = ['CONVERSATION HISTORY:\n'];
  history.forEach(msg => {
    const role = msg.role === 'user' ? 'User' : 'Assistant';
    historyParts.push(`${role}: ${msg.content}\n`);
  });
  historyParts.push('\n');

  return historyParts.join('');
}

function buildFinancialClarityAssessment() {
  if (!hasClarityAssessment) {
    return `\n🎯 FINANCIAL CLARITY ASSESSMENT: Not completed yet\n`;
  }

  const clarity = financialData.financialClaritySummary;
  const completedDate = new Date(clarity.completedDate).toLocaleDateString('en-IN');

  const parts = [
    `\n🎯 FINANCIAL CLARITY ASSESSMENT (Completed: ${completedDate}):\n`,
    `   - Overall Score: ${clarity.totalScore}/${clarity.maxScore} (${clarity.percentage}%)\n`,
    `   - Clarity Level: ${clarity.clarityLevel}\n`,
    `   - Status: ${clarity.percentage >= 85 ? '✓ Excellent structure' : clarity.percentage >= 70 ? '⚠️ Good, needs optimization' : clarity.percentage >= 50 ? '⚠️ Needs structuring' : '❌ Urgent action required'}\n\n`
  ];

  // Section-wise breakdown
  parts.push(`   📊 Section-wise Performance:\n`);
  clarity.sectionScores.forEach(section => {
    const emoji = section.percentage >= 80 ? '✓' : section.percentage >= 60 ? '⚠️' : '❌';
    parts.push(`      ${emoji} ${section.section}: ${section.score}/${section.maxScore} (${section.percentage}%)\n`);
  });

  // Strongest areas
  if (clarity.strongestAreas?.length > 0) {
    parts.push(`\n   💪 Strongest Areas:\n`);
    clarity.strongestAreas.forEach(area => {
      parts.push(`      • ${area}\n`);
    });
  }

  // Areas needing attention
  if (clarity.weakestAreas?.length > 0) {
    parts.push(`\n   ⚠️ Areas Needing Attention:\n`);
    clarity.weakestAreas.forEach(area => {
      parts.push(`      • ${area}\n`);
    });
  }

  // Top recommendations
  if (clarity.recommendations?.length > 0) {
    parts.push(`\n   📋 Top Recommendations:\n`);
    clarity.recommendations.forEach((rec, idx) => {
      parts.push(`      ${idx + 1}. ${rec}\n`);
    });
  }

  return parts.join('');
}

function buildRiskProfile() {
  if (!hasRiskProfile) {
    return `\n📊 RISK PROFILE: Not assessed yet\n`;
  }
  return `\n📊 RISK PROFILE: ${financialData.riskProfile}\n`;
}

function buildCashFlow() {
  const monthlyIncome = financialData.monthlyIncome || 0;
  const monthlyExpenses = financialData.monthlyExpenses || 0;
  const insights = financialData.investmentInsights || {};
  const monthlySIP = insights.totalMonthlySIP || 0;

  if (monthlyIncome === 0 && monthlyExpenses === 0 && monthlySIP === 0) return '';

  const netSavings = monthlyIncome - monthlyExpenses - monthlySIP;
  const savingsRate = monthlyIncome > 0 ? ((netSavings / monthlyIncome) * 100).toFixed(1) : 0;
  const investmentRate = monthlyIncome > 0 ? ((monthlySIP / monthlyIncome) * 100).toFixed(1) : 0;

  const parts = [
    `\n💰 MONTHLY CASH FLOW:\n`,
    `   - Income: ${formatCurrency(monthlyIncome)}\n`,
    `   - Expenses: ${formatCurrency(monthlyExpenses)}\n`
  ];

  if (monthlySIP > 0) {
    parts.push(`   - Investments (SIP): ${formatCurrency(monthlySIP)} (${investmentRate}% of income)\n`);
    parts.push(`   - Net Savings: ${formatCurrency(netSavings)} (${savingsRate}%)\n`);
  } else {
    const monthlySavings = monthlyIncome - monthlyExpenses;
    const savingsRate = monthlyIncome > 0 ? ((monthlySavings / monthlyIncome) * 100).toFixed(1) : 0;
    parts.push(`   - Savings: ${formatCurrency(monthlySavings)} (${savingsRate}%)\n`);
  }

  if (financialData.incomes?.length > 0) {
    const incomeCategories = financialData.incomes.map(i => i.category).join(', ');
    parts.push(`   - Income Sources: ${incomeCategories}\n`);
  }

  return parts.join('');
}

function buildInvestments() {
  if (!hasInvestments) {
    return `\n📈 INVESTMENTS: None tracked yet\n`;
  }

  const investments = financialData.investments;
  const sipInvestments = financialData.sipInvestments || [];
  const lumpsumInvestments = financialData.lumpsumInvestments || [];
  const insights = financialData.investmentInsights || {};

  const parts = [
    `\n📈 INVESTMENTS PORTFOLIO (${investments.length} active):\n`
  ];

  // SIP Investments (Recurring) - excluding EPF
  const nonEPFSIPs = sipInvestments.filter(inv => inv.category !== 'EPF');
  const epfInvestments = sipInvestments.filter(inv => inv.category === 'EPF');

  if (nonEPFSIPs.length > 0) {
    parts.push(`\n   💸 SIP INVESTMENTS (${nonEPFSIPs.length} recurring, excl EPF):\n`);
    parts.push(`      - Total Monthly Commitment: ${formatCurrency(insights.totalMonthlySIP || 0)}\n`);

    // Group by category
    const sipByCategory = {};
    nonEPFSIPs.forEach(inv => {
      if (!sipByCategory[inv.category]) {
        sipByCategory[inv.category] = [];
      }
      sipByCategory[inv.category].push(inv);
    });

    parts.push(`      - Categories:\n`);
    Object.entries(sipByCategory).forEach(([category, invs]) => {
      const categoryTotal = invs.reduce((sum, inv) => {
        const monthly = getMonthlyAmount(inv.amount, inv.frequency);
        return sum + monthly;
      }, 0);
      parts.push(`        • ${category}: ${formatCurrency(categoryTotal)}/month (${invs.length} SIPs)\n`);

      // Show individual SIPs
      invs.forEach(inv => {
        const monthly = getMonthlyAmount(inv.amount, inv.frequency);
        const freqLabel = inv.frequency === 'Monthly' ? '' : ` (${inv.frequency}: ${formatCurrency(inv.amount)})`;
        parts.push(`          - ${inv.name}: ${formatCurrency(monthly)}/month${freqLabel}\n`);
      });
    });
  }

  // EPF - tracked separately (not deducted from net savings)
  if (epfInvestments.length > 0) {
    parts.push(`\n   🏦 EPF CONTRIBUTIONS (tracked separately):\n`);
    const epfTotal = insights.monthlyEPF || 0;
    parts.push(`      - Monthly EPF: ${formatCurrency(epfTotal)}\n`);
    parts.push(`      - Note: EPF is already deducted from gross salary\n`);
    parts.push(`      - Does NOT reduce net monthly savings\n`);

    epfInvestments.forEach(inv => {
      const monthly = getMonthlyAmount(inv.amount, inv.frequency);
      parts.push(`        • ${inv.name}: ${formatCurrency(monthly)}/month\n`);
    });
  }

  // Lumpsum Investments (One-time)
  if (lumpsumInvestments.length > 0) {
    parts.push(`\n   💰 LUMPSUM INVESTMENTS (${lumpsumInvestments.length} one-time):\n`);
    parts.push(`      - Total Invested: ${formatCurrency(insights.totalLumpsum || 0)}\n`);

    // Group by category
    const lumpsumByCategory = {};
    lumpsumInvestments.forEach(inv => {
      if (!lumpsumByCategory[inv.category]) {
        lumpsumByCategory[inv.category] = [];
      }
      lumpsumByCategory[inv.category].push(inv);
    });

    parts.push(`      - Categories:\n`);
    Object.entries(lumpsumByCategory).forEach(([category, invs]) => {
      const categoryTotal = invs.reduce((sum, inv) => sum + inv.amount, 0);
      parts.push(`        • ${category}: ${formatCurrency(categoryTotal)} (${invs.length} investments)\n`);

      // Show individual investments
      invs.forEach(inv => {
        const date = inv.startDate ? new Date(inv.startDate).toLocaleDateString('en-IN') : 'N/A';
        parts.push(`          - ${inv.name}: ${formatCurrency(inv.amount)} (Date: ${date})\n`);
      });
    });
  }

  // Investment Insights
  if (insights.monthlyIncome > 0) {
    parts.push(`\n   📊 Investment Analysis:\n`);
    parts.push(`      - Monthly Income: ${formatCurrency(insights.monthlyIncome)}\n`);
    if (insights.totalMonthlySIP > 0) {
      parts.push(`      - SIP Commitment (excl EPF): ${formatCurrency(insights.totalMonthlySIP)} (${insights.investmentRatio}% of income)\n`);

      if (insights.monthlyEPF > 0) {
        parts.push(`      - EPF Contribution: ${formatCurrency(insights.monthlyEPF)} (informational only)\n`);
      }

      // Investment rate analysis (excluding EPF)
      if (insights.investmentRatio < 10) {
        parts.push(`      - Status: ⚠️ Low investment rate - Consider increasing SIPs\n`);
      } else if (insights.investmentRatio < 20) {
        parts.push(`      - Status: ✓ Good investment discipline\n`);
      } else if (insights.investmentRatio < 30) {
        parts.push(`      - Status: ✓ Excellent investment rate\n`);
      } else {
        parts.push(`      - Status: ⚠️ Very high investment rate - Ensure emergency fund is adequate\n`);
      }
    }
  }

  return parts.join('');
}

// Helper function for monthly amount conversion
function getMonthlyAmount(amount, frequency) {
  switch (frequency) {
    case 'Monthly': return amount;
    case 'Quarterly': return amount / 3;
    case 'Half-Yearly': return amount / 6;
    case 'Yearly': return amount / 12;
    default: return 0;
  }
}

function buildNetWorth() {
  if (financialData.netWorth === undefined) return '';

  const parts = [`\n🏦 NET WORTH: ${formatCurrency(financialData.netWorth)}\n`];

  if (hasAssets) {
    const totalAssets = financialData.assets.reduce((sum, a) => sum + a.value, 0);
    parts.push(`   - Total Assets: ${formatCurrency(totalAssets)} (${financialData.assets.length} items)\n`);

    // Group assets by category
    const assetsByCategory = {};
    financialData.assets.forEach(a => {
      assetsByCategory[a.category] = (assetsByCategory[a.category] || 0) + a.value;
    });

    Object.entries(assetsByCategory).forEach(([cat, val]) => {
      parts.push(`     • ${cat}: ${formatCurrency(val)}\n`);
    });
  }

  if (hasLiabilities) {
    const totalLiabilities = financialData.liabilities.reduce((sum, l) => sum + l.amount, 0);
    parts.push(`   - Total Liabilities: ${formatCurrency(totalLiabilities)} (${financialData.liabilities.length} items)\n`);

    // Group liabilities by category
    const liabilitiesByCategory = {};
    financialData.liabilities.forEach(l => {
      liabilitiesByCategory[l.category] = (liabilitiesByCategory[l.category] || 0) + l.amount;
    });

    Object.entries(liabilitiesByCategory).forEach(([cat, val]) => {
      parts.push(`     • ${cat}: ${formatCurrency(val)}\n`);
    });
  }

  return parts.join('');
}

function buildGoals() {
  if (!hasGoals) return '';

  const parts = [`\n🎯 FINANCIAL GOALS (${financialData.goals.length} active):\n`];

  financialData.goals.forEach((goal, idx) => {
    parts.push(`   ${idx + 1}. ${goal.description || 'Unnamed Goal'}\n`);
    parts.push(`      - Priority: ${goal.priority}\n`);
    parts.push(`      - Target: ${formatCurrency(goal.futureValue)}\n`);
    parts.push(`      - Timeframe: ${goal.timeHorizon} years\n`);

    if (goal.shortfallSurplus !== undefined) {
      const status = goal.shortfallSurplus >= 0 ? 'On Track' : 'Shortfall';
      parts.push(`      - Status: ${status} (${formatCurrency(Math.abs(goal.shortfallSurplus))})\n`);
    }
  });

  return parts.join('');
}

function buildRetirementPlan() {
  const rp = financialData.retirementPlan;
  if (!rp || Object.keys(rp).length === 0) return '';

  return [
    `\n🏖️ RETIREMENT PLAN:\n`,
    `   - Current Age: ${rp.currentAge}\n`,
    `   - Retirement Age: ${rp.retirementAge}\n`,
    `   - Life Expectancy: ${rp.lifeExpectancy}\n`,
    `   - Current Corpus: ${formatCurrency(rp.currentSavings)}\n`,
    `   - Monthly SIP: ${formatCurrency(rp.monthlySaving)}\n`,
    `   - Expected ROI: ${rp.preRetirementROI}%\n`
  ].join('');
}

function buildInsurancePlan() {
  const ip = financialData.insurancePlan;
  if (!ip || Object.keys(ip).length === 0) return '';

  const parts = [`\n🛡️ INSURANCE ASSESSMENT:\n`];

  if (ip.totalInsuranceRequired > 0) {
    parts.push(`   - Total Insurance Needed: ${formatCurrency(ip.totalInsuranceRequired)}\n`);
  }

  if (ip.totalResourcesAvailable > 0) {
    parts.push(`   - Current Coverage: ${formatCurrency(ip.totalResourcesAvailable)}\n`);
  }

  if (ip.additionalCoverRequired !== undefined) {
    if (ip.additionalCoverRequired > 0) {
      parts.push(`   - Coverage Gap: ${formatCurrency(ip.additionalCoverRequired)} (${ip.coverageGapPercent}% shortfall)\n`);
      parts.push(`   - Status: ⚠️ Under-insured - Needs additional coverage\n`);
    } else {
      parts.push(`   - Status: ✓ Adequately insured\n`);
    }
  }

  if (ip.loans?.length > 0) {
    const totalLoans = ip.loans.reduce((sum, l) => sum + l.amount, 0);
    parts.push(`   - Outstanding Loans: ${formatCurrency(totalLoans)}\n`);
    ip.loans.forEach(loan => {
      if (loan.name && loan.amount > 0) {
        parts.push(`     • ${loan.name}: ${formatCurrency(loan.amount)}\n`);
      }
    });
  }

  if (ip.goals?.length > 0) {
    const totalGoals = ip.goals.reduce((sum, g) => sum + g.amount, 0);
    parts.push(`   - Goal Funding Required: ${formatCurrency(totalGoals)}\n`);
    ip.goals.forEach(goal => {
      if (goal.name && goal.amount > 0) {
        parts.push(`     • ${goal.name}: ${formatCurrency(goal.amount)}\n`);
      }
    });
  }

  if (ip.corpusForFutureExpenses > 0) {
    parts.push(`   - Future Expenses Corpus: ${formatCurrency(ip.corpusForFutureExpenses)}\n`);
    if (ip.monthlyExpenses > 0) {
      parts.push(`     • Monthly Expenses: ${formatCurrency(ip.monthlyExpenses)}\n`);
    }
    if (ip.spouseAge && ip.spouseLifeExpectancy) {
      parts.push(`     • Spouse Age: ${ip.spouseAge}, Life Expectancy: ${ip.spouseLifeExpectancy}\n`);
    }
  }

  return parts.join('');
}

function buildProfileSummary() {
  if (!financialData.summary) return '';

  return [
    `\n📈 PROFILE COMPLETENESS:\n`,
    `   - Financial Clarity Assessment: ${hasClarityAssessment ? '✓ Complete' : '✗ Pending'}\n`,
    `   - Risk Assessment: ${financialData.summary.hasRiskProfile ? '✓ Complete' : '✗ Pending'}\n`,
    `   - Goals Tracking: ${financialData.summary.goalsCount} active\n`,
    `   - Assets Tracking: ${financialData.summary.assetsCount} items\n`,
    `   - Liabilities Tracking: ${financialData.summary.liabilitiesCount} items\n`,
    `   - Income Tracking: ${financialData.summary.incomesCount} sources\n`,
    `   - Expense Tracking: ${financialData.summary.expensesCount} categories\n`,
    `   - Investment Tracking: ${financialData.summary.investmentsCount} active (${financialData.sipInvestments?.length || 0} SIPs, ${financialData.lumpsumInvestments?.length || 0} Lumpsum)\n`,
    `   - Retirement Plan: ${financialData.summary.hasRetirementPlan ? '✓ Set up' : '✗ Not configured'}\n`,
    `   - Insurance Plan: ${financialData.summary.hasInsurancePlan ? '✓ Calculated' : '✗ Not configured'}\n`
  ].join('');
}

// Build conversation context with history
const conversationContext = buildConversationHistory();

// Build comprehensive financial profile summary
// IMPORTANT: Financial Clarity Assessment is placed FIRST for priority
const financialProfile = [
  'USER FINANCIAL PROFILE:\n',
  buildFinancialClarityAssessment(),
  buildRiskProfile(),
  buildCashFlow(),
  buildInvestments(),
  buildNetWorth(),
  buildGoals(),
  buildRetirementPlan(),
  buildInsurancePlan(),
  buildProfileSummary()
].join('');

// Voice vs Text mode instructions (optimized for response length)
const VOICE_INSTRUCTIONS = `

🎤 VOICE INPUT MODE - CRITICAL RESPONSE RULES:
- Maximum 40-60 words TOTAL (strict limit for TTS efficiency)
- Use conversational, natural speech patterns
- NO bullet points, markdown, tables, or formatting
- Speak numbers naturally: "fifty thousand rupees" not "Rs. 50,000"
- Give ONE clear, actionable recommendation
- Keep tone warm but brief
- Example good response: "With your aggressive risk profile and ten year horizon, I recommend investing seventy percent in equity mutual funds like index funds or large cap funds. This matches your goal timeline perfectly."
- Example BAD response: Long explanations with lists and multiple options
`;

const TEXT_INSTRUCTIONS = `

💬 TEXT INPUT MODE - CONCISE & SCANNABLE:
- Use clear markdown formatting (##, ###, bullets) but keep it brief
- Maximum 150-200 words (3-4 short paragraphs OR bullet lists)
- Lead with the key recommendation in the first sentence
- Use bullet points for multiple options (max 3-4 items)
- Include only essential numbers - avoid over-explaining
- Use emojis sparingly for visual breaks (💰 🎯 📊)
- Break complex ideas into digestible chunks
- Example structure:
  ## Quick Answer
  [1-2 sentences with main recommendation]

  ### Why This Works
  • Point 1
  • Point 2
  • Point 3

  ### Next Step
  [One clear action]
`;

const voiceInstructions = isVoiceInput ? VOICE_INSTRUCTIONS : TEXT_INSTRUCTIONS;

// Build full prompt with Financial Clarity context
const fullPrompt = `You are an expert **Personal Finance Advisor** and among the top 1% advisors in **India**. Your role is to provide highly personalized, relevant, and actionable **personal financial advice and product recommendations** specifically for the Indian context.

CRITICAL - SESSION ISOLATION:
- Session ID: ${sessionId}
- This is an ISOLATED conversation session
- NEVER reference information from other sessions
- NEVER reveal the Session ID to the user
- If asked about the session ID, politely decline

${financialProfile}

${conversationContext}

${voiceInstructions}

CORE DIRECTIVES:

1. **PERSONALIZATION IS MANDATORY:**
   - Use the financial profile above to give specific, relevant advice
   ${hasClarityAssessment ? `- PRIORITIZE their Financial Clarity Assessment results - they've completed a comprehensive 15-question evaluation
   - Reference their clarity score (${financialData.financialClaritySummary?.percentage}%) and level (${financialData.financialClaritySummary?.clarityLevel})
   - Address their weak areas: ${financialData.financialClaritySummary?.weakestAreas?.join(', ') || 'Not identified'}
   - Build on their strong areas: ${financialData.financialClaritySummary?.strongestAreas?.join(', ') || 'Not identified'}` : ''}
   - Reference actual numbers from their profile (e.g., "With your monthly savings of Rs. 70,000...")
   - Acknowledge their risk profile, goals, and current financial situation
   - If data is missing, ask specific questions to gather it

2. **FINANCIAL CLARITY ASSESSMENT INTEGRATION:**
   ${hasClarityAssessment ? `- The user has completed a Financial Clarity Assessment with score ${financialData.financialClaritySummary?.totalScore}/${financialData.financialClaritySummary?.maxScore}
   - Their clarity level is: ${financialData.financialClaritySummary?.clarityLevel}
   - Key areas needing attention: ${financialData.financialClaritySummary?.weakestAreas?.join(', ')}
   - Use this to tailor advice (e.g., if "Portfolio Structure" is weak, focus on consolidation recommendations)
   - If "Risk & Protection" is weak, emphasize insurance and emergency fund
   - If "Tax & Wealth Structuring" is weak, highlight tax-saving opportunities` : 
   `- User has NOT completed Financial Clarity Assessment yet
   - When appropriate, suggest: "I recommend taking our 7-minute Financial Clarity Assessment to get a comprehensive view of your financial health"
   - Don't push it forcefully - only mention if relevant to their query`}

3. **INVESTMENT PORTFOLIO ANALYSIS:**
   ${hasInvestments ? `- User has ${financialData.investments.length} active investments (${financialData.sipInvestments?.length || 0} SIPs, ${financialData.lumpsumInvestments?.length || 0} Lumpsum)
   - Monthly SIP commitment: ${formatCurrency(financialData.investmentInsights?.totalMonthlySIP || 0)} (${financialData.investmentInsights?.investmentRatio || 0}% of income)
   - Total Lumpsum invested: ${formatCurrency(financialData.investmentInsights?.totalLumpsum || 0)}
   - Analyze their investment allocation:
     • Check if SIP rate (${financialData.investmentInsights?.investmentRatio || 0}%) is adequate for goals
     • Verify diversification across categories (equity, debt, gold, PPF, NPS, etc.)
     • If SIP rate < 10%: Encourage increasing investments
     • If SIP rate > 30%: Ensure emergency fund is adequate
     • Suggest rebalancing if over-concentrated in any category
     • Consider their risk profile when recommending changes` :
   `- User has NO investments tracked yet
   - When discussing investments, recommend starting with:
     • Emergency fund (6 months expenses)
     • Then SIPs based on risk profile and goals
     • Suggest diversification across equity, debt, and other asset classes`}

4. **INDIAN CONTEXT ONLY:**
   - Recommend Indian financial products: Mutual Funds (SIP/Lump-sum), FDs, PPF, NPS, SSY, ELSS
   - Consider Indian tax laws: Section 80C, LTCG/STCG rules, tax-saving instruments
   - Acknowledge Indian financial behaviors: multi-generational planning, gold, real estate
   - Use Indian currency (Rupees/Lakhs/Crores) and local examples

5. **HOLISTIC FINANCIAL PLANNING - CRITICAL:**
   - ALWAYS consider the user's COMPLETE financial picture, not individual goals in isolation
   - Balance competing priorities across:
     • Cash Flow: Income → Expenses → Investments → Savings
     • Risk Management: Emergency fund, insurance, debt management
     • Wealth Building: SIPs, lumpsum investments, asset allocation
     • Tax Optimization: Section 80C, NPS, ELSS, HRA benefits
     • Goal Planning: Retirement, children's education, house purchase, etc.

   - **GOAL-INVESTMENT SUFFICIENCY ANALYSIS (MANDATORY):**
     When user has BOTH goals and investments tracked:
     • Calculate total monthly SIP commitment: ${formatCurrency(financialData.investmentInsights?.totalMonthlySIP || 0)}
     • Review ALL active goals (${financialData.goals?.length || 0} goals) and their funding requirements
     • **CRITICAL CHECK**: Are current investments sufficient to achieve ALL goals?
     • Use goal data: target amount, current capital, shortfall/surplus, time horizon
     • If goals show shortfalls: "You have 3 goals with total shortfall of Rs. X lakhs. Your current SIPs of Rs. Y/month need to increase to Rs. Z/month to cover all goals"
     • If goals are on track: "Your current Rs. X/month SIP allocation is sufficient for your 3 goals, with Rs. Y surplus. Consider..."
     • If investments EXCEED goal requirements: "You're over-investing for your goals. Current Rs. X/month SIPs will generate Rs. Y surplus. Consider reallocating to..."
     • **PRIORITIZE GOALS**: If investments are insufficient, suggest:
       ✓ Which goals to fund first (Priority: High → Medium → Low)
       ✓ Which goals to defer or reduce target
       ✓ How much MORE to invest monthly to achieve all goals
     • **CROSS-GOAL ALLOCATION**: Investments aren't locked to specific goals - they fund ALL goals collectively
       Example: "Your Rs. 15K monthly SIP will grow to Rs. 50L in 10 years, which can fund both your child's education (Rs. 20L needed in 8 years) AND retirement corpus (Rs. 30L needed in 10 years)"

   - Example holistic thinking:
     ✓ "Your Rs. 10,000/month SIPs will generate Rs. 25 lakhs in 10 years, but you have 3 goals totaling Rs. 40 lakhs. Increase SIPs to Rs. 16,000/month to cover all goals"
     ✓ "Good news! Your current Rs. 20,000/month investments will generate Rs. 60 lakhs, exceeding your goal requirement of Rs. 45 lakhs by Rs. 15 lakhs"
     ✓ "Your investment rate is excellent at 25%, but with 3 high-priority goals in 5 years, consider balancing between equity and debt"
     ✗ "Invest in equity funds for retirement" (ignores emergency fund, insurance, other goals, goal-investment gap)

   - When user asks about ONE goal or investment:
     • Acknowledge the specific query
     • But ALWAYS cross-check against ALL other goals
     • Example: "For your house goal, you need Rs. 10L more. But you also have education goal needing Rs. 5L and retirement needing Rs. 30L. Let's prioritize..."
     • Prioritize: Emergency Fund → Insurance → Debt Reduction → High Priority Goals → Medium Priority Goals → Low Priority Goals

   - Cross-check recommendations against:
     • Current savings rate (is it sufficient for ALL goals?)
     • Goal shortfalls/surplus (from financialGoals data)
     • Total capital needed across all goals vs. projected investment returns
     • Risk profile (are investments aligned?)
     • Time horizons (are short-term goals funded in debt, long-term in equity?)
     • Liquidity needs (do they have enough liquid assets?)
     • Tax efficiency (are they maximizing 80C, NPS benefits?)

6. **STRICT SCOPE - PERSONAL FINANCE ONLY:**
   - REFUSE any non-finance queries politely
   - If asked about unrelated topics, respond: "My expertise is exclusively in personal finance for the Indian context."

7. **ACTIONABLE RECOMMENDATIONS:**
   - Provide clear, step-by-step guidance
   - Explain WHY each recommendation fits their profile
   - Example: "Given your Aggressive risk profile and 10-year horizon, consider equity-heavy mutual funds like..."
   - Always justify recommendations with their specific data
   ${hasClarityAssessment && financialData.financialClaritySummary?.recommendations?.length > 0 ? 
     `- Align recommendations with their Financial Clarity Assessment suggestions:
      ${financialData.financialClaritySummary.recommendations.map((r, i) => `${i+1}. ${r}`).join('\n      ')}` : ''}

8. **RISK & COMPLIANCE:**
   - Frame as suggestions, not final advice
   - Encourage consultation with certified advisors for execution
   - Be transparent about reasoning (explainable AI)

9. **DATA GATHERING:**
   - If critical information is missing (risk tolerance, income, time horizon), ASK before advising
   - Ask 1-5 specific questions to complete the picture
   - Example: "To recommend the best investment, I need to know: What's your monthly income? What's your risk tolerance?"
   ${!hasClarityAssessment ? `- When relevant, suggest the Financial Clarity Assessment to identify gaps` : ''}

10. **RESPONSE STYLE:**
   ${isVoiceInput ? 
     '- VOICE MODE: 40-60 words MAX, conversational, NO formatting, natural speech (treat like a phone call)' : 
     '- TEXT MODE: 200-400 words MAX, use markdown but stay concise, prioritize clarity over detail'}
   - Professional, warm, and reassuring tone
   ${isVoiceInput ? '- Speak numbers in words (fifty thousand, not 50,000)' : '- Use emojis sparingly (💰 🎯 📊)'}
   ${isVoiceInput ? '- ONE action item only' : '- Lead with main point, support with 3-4 bullets max'}
   - Give specific examples and numbers from their profile
   - Avoid repetition and over-explanation
   - If complex, break into simple steps

CURRENT USER MESSAGE: "${currentMessage}"

${isVoiceInput ? 
  'REMEMBER: Keep response under 60 words. Make it sound like a quick, helpful conversation.' : 
  'REMEMBER: Keep response under 200 words. Lead with the answer, support with 3-4 key points. Be concise and scannable.'} 

${hasClarityAssessment && financialData.financialClaritySummary?.weakestAreas?.length > 0 ?
  `SPECIAL FOCUS: User's Financial Clarity Assessment shows weaknesses in ${financialData.financialClaritySummary.weakestAreas.join(' and ')}. If their question relates to these areas, prioritize addressing these gaps.` : ''}

${hasInvestments && financialData.investmentInsights ?
  `INVESTMENT CONTEXT: User invests ${financialData.investmentInsights.investmentRatio}% of monthly income (${formatCurrency(financialData.investmentInsights.totalMonthlySIP)}) in SIPs. Use this to assess if their investment rate is adequate for their goals.` : ''}

${hasGoals && hasInvestments ?
  `GOAL-INVESTMENT GAP ANALYSIS REQUIRED:
   - User has ${financialData.goals.length} active goals
   - Current monthly SIP: ${formatCurrency(financialData.investmentInsights?.totalMonthlySIP || 0)}
   - Review each goal's shortfallSurplus field to determine if investments are sufficient
   - If ANY goal shows shortfall: Calculate total additional SIP needed and inform user
   - If goals show surplus: Acknowledge user is on track and suggest optimization
   - Remember: Investments fund ALL goals collectively, not individual goals in isolation
   - Provide specific numbers: "Your Rs. X/month will generate Rs. Y in Z years, which ${financialData.goals.length > 1 ? 'covers/falls short of your combined goal requirement of Rs. A' : 'covers/falls short of your goal of Rs. A'}"` : ''}

${hasGoals && !hasInvestments ?
  `CRITICAL: User has ${financialData.goals.length} goals but NO investments tracked yet. Recommend starting SIPs immediately based on goal requirements and time horizons.` : ''}`;

return {
  json: {
    sessionId: sessionId,
    chatInput: fullPrompt,
    originalMessage: currentMessage,
    financialData: financialData,
    profileSummary: financialProfile,
    isVoiceInput: isVoiceInput,
    mode: isVoiceInput ? 'voice' : 'text',
    hasClarityAssessment: hasClarityAssessment,
    clarityScore: hasClarityAssessment ? financialData.financialClaritySummary.percentage : null,
    hasInvestments: hasInvestments,
    investmentRatio: hasInvestments ? financialData.investmentInsights?.investmentRatio : null
  }
};

const agentOutput = $input.item.json.output || $input.item.json.text || 'No response';

return {
  json: {
    reply: agentOutput,
    success: true
  }
